+  with(...args: any[]): MatchEachExpression<input, output> {
+    const handler = args[args.length - 1];
+    const patterns: Pattern<any>[] = [args[0]];
+    let predicate: ((value: input) => unknown) | undefined;
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns.push(...args.slice(1, -1));
+    return this.next({ kind: 'clause', patterns, predicate, handler });
+  }
+
+  when(predicate: (value: input) => unknown, handler: (selection: input, value: input) => output): MatchEachExpression<input, output> {
+    return this.next({ kind: 'clause', patterns: [], predicate, handler: (_selection, value) => handler(value, value) });
+  }
